import React from "react";

const ProductReviews = ({ reviews }) => {
  if (reviews.length === 0)
    return <p className="text-gray-500">Chưa có đánh giá nào.</p>;

  return (
    <div className="space-y-4 max-h-80 overflow-y-auto">
      {reviews.map((rv, index) => (
        <div
          key={index}
          className="bg-pink-50 p-4 rounded-xl border border-pink-100"
        >
          <b className="text-[#4b2c35]">{rv.name}</b>

          <div className="text-yellow-500">
            {"★".repeat(rv.rating)}
            <span className="text-gray-300">
              {"★".repeat(5 - rv.rating)}
            </span>
          </div>

          <p className="text-gray-700 mt-1">{rv.comment}</p>
        </div>
      ))}
    </div>
  );
};

export default ProductReviews;
